// ───── FILTER + KIES ─────
// criteria = { leeftijd, duur, plek, sociaal }
window.kiesIdee = function (criteria, vorigeId) {
  const passend = window.IDEEEN.filter((i) =>
    i.leeftijd.includes(criteria.leeftijd) &&
    i.duur.includes(criteria.duur) &&
    i.plek.includes(criteria.plek) &&
    i.sociaal.includes(criteria.sociaal)
  );
  if (!passend.length) return null;
  // probeer een ander idee dan vorige keer
  const opties = passend.length > 1 && vorigeId != null
    ? passend.filter((i) => i.id !== vorigeId)
    : passend;
  return opties[Math.floor(Math.random() * opties.length)];
};
